parameters.jsCode:
// Este workflow se ejecuta manualmente subiendo un CSV
// Formato esperado del CSV (exportado de Apollo o Evaboot):
// empresa, rubro, zona, web, telefono, nombre_contacto, cargo_contacto, email_contacto

return [{
  json: {
    mensaje: "Subí tu CSV usando el nodo 'Read Binary Files' o ejecutá este workflow después de subir el archivo a una carpeta"
  }
}];

// Limpiar y transformar datos del CSV
const rows = $input.all()[0].json.data || $input.all();

return rows.map(row => {
  // Normalizar campos
  const email = (row.email || row.Email || row.email_contacto || '').toLowerCase().trim();
  const nombre = (row.nombre || row.Nombre || row.nombre_contacto || row.first_name || '').trim();
  const empresa = (row.empresa || row.Empresa || row.company || row.organization || '').trim();
  const cargo = (row.cargo || row.Cargo || row.title || row.cargo_contacto || '').toLowerCase();
  const telefono = (row.telefono || row.Teléfono || row.phone || row.telefono_empresa || '').trim();
  const web = (row.web || row.Web || row.website || row.Website || '').trim();
  const rubro = (row.rubro || row.Rubro || row.industry || row.Industry || 'Otros').trim();
  const zona = (row.zona || row.Zona || row.location || row.Location || 'Argentina').trim();

  // Detectar si el cargo es de compras
  const isCompras = /compras|abastecimiento|purchasing|supply|adquisiciones/i.test(cargo);

  return {
    json: {
      empresa: empresa,
      rubro: rubro,
      zona: zona,
      empleados_aprox: row.empleados || row['# employees'] || '',
      web: web,
      nombre_contacto: nombre,
      cargo_contacto: cargo,
      email_contacto: email,
      telefono_empresa: telefono,
      estado: isCompras ? 'pendiente' : 'verificar_cargo',
      email_enviado_1: '',
      email_enviado_2: '',
      email_enviado_3: '',
      fecha_ultimo_contacto: '',
      fecha_respuesta: '',
      categoria_respuesta: '',
      resumen_respuesta: '',
      accion_sugerida: '',
      urgencia: '',
      notas_call: isCompras ? '' : 'Cargo no claramente de compras - verificar',
      origen: 'apollo_import_' + DateTime.now().toFormat('yyyy-MM-dd')
    }
  };
}).filter(row => row.json.email_contacto && row.json.email_contacto.includes('@'));

parameters.prompt:
=Analizá si este cargo es de área de compras, abastecimiento o similar.

Cargo: {{ $json.cargo_contacto }}
Empresa: {{ $json.empresa }}

Respondé con un JSON:
{
  "es_compras": true/false,
  "confianza": "alta/media/baja",
  "razon": "breve explicación"
}

Si el cargo menciona compras, abastecimiento, purchasing, supply chain, adquisiciones, o similar, es de compras.
Si es de finanzas, ventas, marketing, IT, no es de compras.

parameters.jsCode:
// Parsear respuesta de AI y actualizar estado
const aiResponse = $input.first().json.text || '{}';

try {
  const parsed = JSON.parse(aiResponse.replace(/```json\s*|\s*```/g, ''));
  const esCompras = parsed.es_compras === true || parsed.es_compras === 'true';

  return [{
    json: {
      ...$input.first().json,
      estado: esCompras ? 'pendiente' : 'no_es_compras',
      notas_call: (esCompras ? '' : 'Cargo: ') + parsed.razon || ''
    }
  }];
} catch (e) {
  // Si falla el parseo, mantener estado anterior
  return [{
    json: {
      ...$input.first().json
    }
  }];
}

